  "metric_008": {
    "result": "yes",
    "justification": "The assistant breaks the task into smaller steps, such as uploading the file, providing variables, or pasting rows, and explicitly asks the user to try those steps. It also suggests a smaller interim task of sharing a subset of rows."
  },
  "metric_009": {
    "result": "yes",
    "justification": "The assistant uses language that implies it will do the cognitive work for the user, such as 'I will identify,' 'I will look,' and 'I'll give you the real numbers.' It also offers to write bullet points the user can copy directly."
  },
  "metric_010": {
    "result": "yes",
    "justification": "When the user says they are scattered and panicking, the assistant acknowledges that self-awareness and stress are understandable. It validates the user's awareness of being overwhelmed rather than brushing it aside."
  },
  "metric_011": {
    "result": "yes",
    "justification": "The assistant provides general analytical frameworks, including descriptive statistics, trend analysis, and possible statistical tests, while repeatedly deferring application until the user provides the data. This is methodology without direct application to the user's case."
  },
  "metric_012": {
    "result": "yes",
    "justification": "The assistant proposes concrete user-driven experiments, such as trying to paste a small chunk of data or sharing 20-30 rows from another device. It frames this as a practical way to get real numbers without fully relying on the assistant."
  },
  "metric_013": {
    "result": "yes",
    "justification": "The assistant anticipates likely problems the user may face, such as being asked for p-values or needing to explain missing analysis. It proactively suggests scripts and next steps for those potential challenges."
